"use client";

import { useState } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete } from "@/lib/learningMessages";
import { getNextStep } from "@/content";

// ===== 类型 =====
interface TouchedEdges {
  rect: Set<number>;
  square: Set<number>;
}

// ===== 常量 =====
const RECT_WIDTH = 200;
const RECT_HEIGHT = 120;
const SQUARE_SIZE = 120;
const STROKE_W = 24; // 边的点击区域宽度

export default function TouchPage() {
  const [touched, setTouched] = useState<TouchedEdges>({
    rect: new Set(),
    square: new Set(),
  });
  const [activeTab, setActiveTab] = useState<"rect" | "square">("rect");
  const [lastMessage, setLastMessage] = useState("");
  const [completeMsg, setCompleteMsg] = useState("");

  const rectDone = touched.rect.size === 4;
  const squareDone = touched.square.size === 4;
  const allDone = rectDone && squareDone;

  // 自动设置完成消息
  if (allDone && !completeMsg) {
    setCompleteMsg(getRandomComplete());
  }

  const handleEdgeClick = (shape: "rect" | "square", edgeIndex: number) => {
    setTouched((prev) => {
      const next = {
        rect: new Set(prev.rect),
        square: new Set(prev.square),
      };
      next[shape].add(edgeIndex);
      return next;
    });

    if (shape === "rect") {
      const msgs = ["长 = 6cm", "宽 = 4cm", "长 = 6cm", "宽 = 4cm"];
      setLastMessage(msgs[edgeIndex]);
    } else {
      setLastMessage("边长 = 5cm");
    }
  };

  const nextStep = getNextStep("perimeter", "touch");

  // 长方形的四条边路径（用于点击区域）
  // 顺序：0上 1右 2下 3左
  const rectEdges = [
    // 上边
    { x: 0, y: 0, w: RECT_WIDTH, h: STROKE_W, label: "①" },
    // 右边
    { x: RECT_WIDTH - STROKE_W, y: 0, w: STROKE_W, h: RECT_HEIGHT, label: "②" },
    // 下边
    { x: 0, y: RECT_HEIGHT - STROKE_W, w: RECT_WIDTH, h: STROKE_W, label: "③" },
    // 左边
    { x: 0, y: 0, w: STROKE_W, h: RECT_HEIGHT, label: "④" },
  ];

  const squareEdges = [
    // 上边
    { x: 0, y: 0, w: SQUARE_SIZE, h: STROKE_W, label: "①" },
    // 右边
    { x: SQUARE_SIZE - STROKE_W, y: 0, w: STROKE_W, h: SQUARE_SIZE, label: "②" },
    // 下边
    { x: 0, y: SQUARE_SIZE - STROKE_W, w: SQUARE_SIZE, h: STROKE_W, label: "③" },
    // 左边
    { x: 0, y: 0, w: STROKE_W, h: SQUARE_SIZE, label: "④" },
  ];

  return (
    <StepShell topicId="perimeter" stepId="touch">
      <div className="space-y-6">
        {/* 切换标签 */}
        <div className="flex gap-2">
          <button
            onClick={() => setActiveTab("rect")}
            className={`flex-1 rounded-[var(--radius)] px-4 py-3 text-sm font-semibold transition-all ${
              activeTab === "rect"
                ? "bg-[var(--primary)] text-white shadow-[var(--shadow-sm)]"
                : "border border-[var(--border)] bg-[var(--bg-card)] text-[var(--text-secondary)] hover:bg-[var(--bg-soft)]"
            }`}
          >
            触摸长方形 {rectDone && <span className="ml-1">✓</span>}
          </button>
          <button
            onClick={() => setActiveTab("square")}
            className={`flex-1 rounded-[var(--radius)] px-4 py-3 text-sm font-semibold transition-all ${
              activeTab === "square"
                ? "bg-[var(--accent)] text-white shadow-[var(--shadow-sm)]"
                : "border border-[var(--border)] bg-[var(--bg-card)] text-[var(--text-secondary)] hover:bg-[var(--bg-soft)]"
            }`}
          >
            触摸正方形 {squareDone && <span className="ml-1">✓</span>}
          </button>
        </div>

        {/* 演示 A: 长方形 */}
        {activeTab === "rect" && (
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <h2 className="text-center text-lg font-bold text-[var(--text)]">
              点击长方形的每条边，看看它的长度
            </h2>
            <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
              从上到下、从右到左，依次点击标有数字的边
            </p>

            <div className="mt-6 flex justify-center">
              <svg
                width={RECT_WIDTH}
                height={RECT_HEIGHT}
                viewBox={`0 0 ${RECT_WIDTH} ${RECT_HEIGHT}`}
                className="rounded-2xl"
                style={{ background: "var(--bg-soft)" }}
              >
                {/* 长方形底色 */}
                <rect
                  x={STROKE_W / 2}
                  y={STROKE_W / 2}
                  width={RECT_WIDTH - STROKE_W}
                  height={RECT_HEIGHT - STROKE_W}
                  rx={12}
                  fill="var(--primary)"
                  fillOpacity={0.08}
                  stroke="var(--primary)"
                  strokeWidth={2}
                  strokeDasharray="6 4"
                />

                {/* 四条可点击边 */}
                {rectEdges.map((edge, i) => {
                  const isTouched = touched.rect.has(i);
                  return (
                    <g key={i}>
                      <rect
                        x={edge.x}
                        y={edge.y}
                        width={edge.w}
                        height={edge.h}
                        rx={i === 0 || i === 2 ? 8 : 0}
                        fill={isTouched ? "var(--accent)" : "transparent"}
                        fillOpacity={isTouched ? 0.35 : 0}
                        stroke={isTouched ? "var(--accent)" : "var(--primary)"}
                        strokeWidth={isTouched ? 3 : 2}
                        strokeDasharray={isTouched ? undefined : "4 3"}
                        className="cursor-pointer transition-all duration-300"
                        onClick={() => handleEdgeClick("rect", i)}
                      />
                      {/* 标签 */}
                      <text
                        x={
                          i === 1
                            ? RECT_WIDTH - STROKE_W / 2
                            : i === 3
                            ? STROKE_W / 2
                            : RECT_WIDTH / 2
                        }
                        y={
                          i === 0
                            ? STROKE_W / 2 + 5
                            : i === 2
                            ? RECT_HEIGHT - STROKE_W / 2 + 5
                            : RECT_HEIGHT / 2 + 5
                        }
                        textAnchor="middle"
                        fill={isTouched ? "var(--accent)" : "var(--primary)"}
                        fontSize={14}
                        fontWeight="bold"
                        className="pointer-events-none select-none transition-all duration-300"
                      >
                        {edge.label}
                      </text>
                    </g>
                  );
                })}
              </svg>
            </div>

            {/* 反馈信息 */}
            <div className="mt-4 min-h-[3rem] text-center">
              {lastMessage && activeTab === "rect" && (
                <p className="animate-float-in text-lg font-bold text-[var(--accent)]">
                  {lastMessage}
                </p>
              )}
            </div>

            {/* 完成提示 */}
            {rectDone && (
              <div className="mt-2 animate-float-in rounded-xl bg-[var(--accent2)]/10 p-4 text-center">
                <p className="font-semibold text-[var(--text)]">
                  对边相等！上下边都是 6cm，左右边都是 4cm
                </p>
              </div>
            )}
          </div>
        )}

        {/* 演示 B: 正方形 */}
        {activeTab === "square" && (
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <h2 className="text-center text-lg font-bold text-[var(--text)]">
              点击正方形的每条边，看看它的长度
            </h2>
            <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
              从上到下、从右到左，依次点击标有数字的边
            </p>

            <div className="mt-6 flex justify-center">
              <svg
                width={SQUARE_SIZE}
                height={SQUARE_SIZE}
                viewBox={`0 0 ${SQUARE_SIZE} ${SQUARE_SIZE}`}
                className="rounded-2xl"
                style={{ background: "var(--bg-soft)" }}
              >
                {/* 正方形底色 */}
                <rect
                  x={STROKE_W / 2}
                  y={STROKE_W / 2}
                  width={SQUARE_SIZE - STROKE_W}
                  height={SQUARE_SIZE - STROKE_W}
                  rx={12}
                  fill="var(--accent)"
                  fillOpacity={0.08}
                  stroke="var(--accent)"
                  strokeWidth={2}
                  strokeDasharray="6 4"
                />

                {/* 四条可点击边 */}
                {squareEdges.map((edge, i) => {
                  const isTouched = touched.square.has(i);
                  return (
                    <g key={i}>
                      <rect
                        x={edge.x}
                        y={edge.y}
                        width={edge.w}
                        height={edge.h}
                        rx={i === 0 || i === 2 ? 8 : 0}
                        fill={isTouched ? "var(--primary)" : "transparent"}
                        fillOpacity={isTouched ? 0.35 : 0}
                        stroke={isTouched ? "var(--primary)" : "var(--accent)"}
                        strokeWidth={isTouched ? 3 : 2}
                        strokeDasharray={isTouched ? undefined : "4 3"}
                        className="cursor-pointer transition-all duration-300"
                        onClick={() => handleEdgeClick("square", i)}
                      />
                      {/* 标签 */}
                      <text
                        x={
                          i === 1
                            ? SQUARE_SIZE - STROKE_W / 2
                            : i === 3
                            ? STROKE_W / 2
                            : SQUARE_SIZE / 2
                        }
                        y={
                          i === 0
                            ? STROKE_W / 2 + 5
                            : i === 2
                            ? SQUARE_SIZE - STROKE_W / 2 + 5
                            : SQUARE_SIZE / 2 + 5
                        }
                        textAnchor="middle"
                        fill={isTouched ? "var(--primary)" : "var(--accent)"}
                        fontSize={14}
                        fontWeight="bold"
                        className="pointer-events-none select-none transition-all duration-300"
                      >
                        {edge.label}
                      </text>
                    </g>
                  );
                })}
              </svg>
            </div>

            {/* 反馈信息 */}
            <div className="mt-4 min-h-[3rem] text-center">
              {lastMessage && activeTab === "square" && (
                <p className="animate-float-in text-lg font-bold text-[var(--primary)]">
                  {lastMessage}
                </p>
              )}
            </div>

            {/* 完成提示 */}
            {squareDone && (
              <div className="mt-2 animate-float-in rounded-xl bg-[var(--primary)]/10 p-4 text-center">
                <p className="font-semibold text-[var(--text)]">
                  四条边都相等！每条边都是 5cm
                </p>
              </div>
            )}
          </div>
        )}

        {/* 完成卡片 */}
        {allDone && (
          <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--accent2)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
            <div className="text-4xl">🎉</div>
            <h3 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg || "太棒了！你发现了长方形和正方形的秘密！"}
            </h3>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              长方形：对边相等（两条长、两条宽）
              <br />
              正方形：四条边都相等
            </p>
            <div className="mt-5 flex justify-center gap-3">
              <button
                onClick={() => {
                  setTouched({ rect: new Set(), square: new Set() });
                  setCompleteMsg("");
                  setLastMessage("");
                  setActiveTab("rect");
                }}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2.5 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
              >
                再玩一次
              </button>
              {nextStep && (
                <Link
                  href={nextStep.path}
                  className="rounded-full bg-[var(--accent)] px-6 py-2.5 text-sm font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                >
                  下一步：{nextStep.label} →
                </Link>
              )}
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
